// ADSREnvelope.h (3 instances: ampEnv, modEnv1, modEnv2 in SynthVoice)
class ADSREnvelope {
    float attackMs     = 0.0f;
    float decayMs      = 0.0f;
    float sustainLevel = 1.0f;
    float releaseMs    = 0.0f;
    float currentLevel = 0.0f;
    float targetVelocity = 1.0f;
    bool looping = false;
};

// BlockParams.h defaults:
// Amp: ampAttack=0, ampDecay=0, ampSustain=1, ampRelease=0, ampAmount=1, ampLoop=false
// Mod1: mod1Attack=0, mod1Decay=0, mod1Sustain=1, mod1Release=0, mod1Amount=0, mod1Target=8(None), mod1Loop=false
// Mod2: mod2Attack=0, mod2Decay=0, mod2Sustain=1, mod2Release=0, mod2Amount=0, mod2Target=8(None), mod2Loop=false

// APVTS defaults (PluginProcessor.cpp):
// amp_amount default=1.0, mod1_amount default=0.5, mod2_amount default=0.5

// LFO.h
class LFO {
    float rate = 1.0f;
    int waveform = 0;  // 0=Sine, 1=Triangle, 2=Saw, 3=Square
    float depth = 1.0f;
};

// APVTS defaults (PluginProcessor.cpp):
// lfo1_rate: NormalisableRange(0.01, 40.0, 0.01, 0.3), default=2.0
// lfo1_depth: NormalisableRange(0.0, 1.0), default=0.0
// lfo1_wave: {Sine,Tri,Saw,Sq}, default=0 (Sine)
// lfo1_target: default=9 (None)
// lfo1_mode: {Free,Trig}, default=0 (Free)
// lfo2_rate: default=0.5
// lfo2_depth: default=0.0
// lfo2_wave: default=0 (Sine)
// lfo2_target: default=9 (None)
// lfo2_mode: default=0 (Free)

