function init(ac: AudioContext): void {
  ctx = ac
  for (let i = 0; i < 3; i++) {
    envGainNodes[i] = ac.createGain()
    envGainNodes[i]!.gain.value = 0  // Closed gate
  }
  for (let i = 0; i < 2; i++) {
    createLfoNodes(ac, i)
  }
}

