function triggerAttack(velocity = 1): void {
  if (!ctx) return
  for (let i = 0; i < 3; i++) {
    triggerEnvAttack(i, velocity)
  }
  // Retrigger LFOs in trigger mode
  for (let i = 0; i < 2; i++) {
    if (lfos[i]!.mode.value === 'trigger' && ctx) {
      createLfoNodes(ctx, i)
      applyLfoRouting()
    }
  }
  startLfoCallbackPolling()
}

