function scheduleEnvLoop(idx: number, velocity: number, cycleTime: number): void {
  envLoopTimers[idx] = setTimeout(() => {
    if (envs[idx]!.loop.value && envs[idx]!.target.value !== 'none') {
      triggerEnvAttack(idx, velocity)
    }
  }, cycleTime * 1000)
}

