// ADSREnvelope::processSample (ADSREnvelope.cpp):
// Gleiche Logik, per-sample statt per-rAF-frame:
// Attack: linear ramp (currentLevel += attackIncr)
// Decay: linear ramp (currentLevel += decayIncr)
// Sustain: holds decayTarget
// Release: RC-discharge e^(-t/tau), tau=releaseMs/5
// Loop: re-enters Attack from Sustain

Original-Code (TypeScript):
function computeSustainLevel(idx: number, elapsed: number): number {
  const env = envs[idx]!
  const atk = env.attackMs.value
  const dec = env.decayMs.value
  const sus = env.sustain.value
  if (elapsed < atk) return atk > 0 ? elapsed / atk : 1
  if (elapsed < atk + dec) return 1 - ((elapsed - atk) / Math.max(dec, 1)) * (1 - sus)
  return sus
}

