// LFO::reset (LFO.cpp):
void LFO::reset() { phase = 0.0; }

// LFO.h: 0=Sine, 1=Triangle, 2=Saw, 3=Square
// LFO::processSample (LFO.cpp):
switch (waveform) {
    case 0: output = static_cast<float>(std::sin(phase * TWO_PI)); break;
    case 1: { // Triangle
        double t = phase;
        output = static_cast<float>(t < 0.5 ? (4.0 * t - 1.0) : (3.0 - 4.0 * t));
        break;
    }
    case 2: output = static_cast<float>(2.0 * phase - 1.0); break; // Saw
    case 3: output = phase < 0.5 ? 1.0f : -1.0f; break; // Square
}

